create table if not exists public.site_settings (
  id integer primary key default 1,
  site_name varchar(120) not null,
  tagline varchar(255) not null,
  description text not null,
  primary_domain varchar(255) not null,
  secondary_domain varchar(255) not null,
  media_domain varchar(255),
  hero_title text not null,
  hero_summary text not null,
  hero_primary_cta_label varchar(120) not null,
  hero_primary_cta_url varchar(255) not null,
  hero_secondary_cta_label varchar(120) not null,
  hero_secondary_cta_url varchar(255) not null,
  social_links jsonb not null default '[]'::jsonb,
  footer_groups jsonb not null default '[]'::jsonb,
  home_signals jsonb not null default '[]'::jsonb,
  home_stats jsonb not null default '[]'::jsonb,
  copyright_text text not null,
  date_updated timestamptz,
  constraint site_settings_singleton check (id = 1)
);
create table if not exists public.about_page (
  id integer primary key default 1,
  title text not null,
  summary text not null,
  sections jsonb not null default '[]'::jsonb,
  date_updated timestamptz,
  constraint about_page_singleton check (id = 1)
);
create table if not exists public.articles (
  id uuid primary key default gen_random_uuid(),
  status varchar(20) not null default 'draft',
  sort integer,
  date_created timestamptz,
  date_updated timestamptz,
  slug varchar(255) not null,
  title varchar(255) not null,
  summary text not null,
  body text not null,
  published_at timestamptz,
  reading_time varchar(50),
  authors jsonb not null default '[]'::jsonb,
  tags jsonb not null default '[]'::jsonb,
  cover_image_url text,
  cover_accent varchar(255)
);
create table if not exists public.jobs (
  id uuid primary key default gen_random_uuid(),
  status varchar(20) not null default 'draft',
  sort integer,
  date_created timestamptz,
  date_updated timestamptz,
  slug varchar(255) not null,
  company_name varchar(255) not null,
  role_title varchar(255) not null,
  salary varchar(255),
  supports_remote boolean not null default false,
  work_mode varchar(120),
  location varchar(255),
  summary text not null,
  description text not null,
  responsibilities jsonb not null default '[]'::jsonb,
  apply_url text,
  apply_note text,
  contact_label varchar(120),
  contact_value varchar(255),
  published_at timestamptz,
  expires_at timestamptz,
  tags jsonb not null default '[]'::jsonb
);
create table if not exists public.events (
  id uuid primary key default gen_random_uuid(),
  status varchar(20) not null default 'draft',
  event_status varchar(20) not null default 'upcoming',
  sort integer,
  date_created timestamptz,
  date_updated timestamptz,
  slug varchar(255) not null,
  title varchar(255) not null,
  summary text not null,
  content text not null,
  start_at timestamptz not null,
  end_at timestamptz not null,
  location varchar(255),
  venue varchar(255),
  city varchar(120),
  registration_url text,
  registration_note text,
  cover_image_url text,
  tags jsonb not null default '[]'::jsonb
);
create table if not exists public.contributor_roles (
  id uuid primary key default gen_random_uuid(),
  status varchar(20) not null default 'draft',
  sort integer,
  date_created timestamptz,
  date_updated timestamptz,
  slug varchar(255) not null,
  name varchar(255) not null,
  description text not null
);
create table if not exists public.contributors (
  id uuid primary key default gen_random_uuid(),
  status varchar(20) not null default 'draft',
  sort integer,
  date_created timestamptz,
  date_updated timestamptz,
  slug varchar(255) not null,
  name varchar(255) not null,
  avatar_url text,
  avatar_seed varchar(120),
  headline varchar(255),
  bio text not null,
  role_slugs jsonb not null default '[]'::jsonb,
  twitter_url text,
  wechat varchar(120),
  telegram varchar(120)
);
create table if not exists public.geekdaily_episodes (
  id uuid primary key default gen_random_uuid(),
  status varchar(20) not null default 'draft',
  sort integer,
  date_created timestamptz,
  date_updated timestamptz,
  episode_number integer not null,
  slug varchar(255) not null,
  title varchar(255) not null,
  summary text not null,
  body text not null,
  published_at timestamptz not null,
  tags jsonb not null default '[]'::jsonb,
  items jsonb not null default '[]'::jsonb
);

